previewCss:
.darma-loader-uiverse-dashboard-skeleton-card {
  width: 224px;
  height: 256px;
  border-radius: 18px;
  padding: 16px;
  display: flex;
  flex-direction: column;
  gap: 16px;
  background: var(--loader-color, #d4d4d4);
}
.darma-loader-uiverse-dashboard-skeleton-card__thumbnail,
.darma-loader-uiverse-dashboard-skeleton-card__rows span {
  background: linear-gradient(90deg, rgba(115,115,115,.22), color-mix(in srgb, var(--loader-secondary-color, #ffffff) 35%, transparent), rgba(115,115,115,.22));
  background-size: 300% 100%;
  animation: darma-loader-uiverse-dashboard-skeleton-card-skeletonSweep 1.2s ease-in-out infinite;
  border-radius: 10px;
}
.darma-loader-uiverse-dashboard-skeleton-card__thumbnail { width: 100%; height: 128px; }
.darma-loader-uiverse-dashboard-skeleton-card__rows { display: flex; flex-direction: column; gap: 10px; }
.darma-loader-uiverse-dashboard-skeleton-card__rows span { height: 14px; width: 100%; }
.darma-loader-uiverse-dashboard-skeleton-card__rows span:nth-child(2) { width: 80%; }
.darma-loader-uiverse-dashboard-skeleton-card__rows span:nth-child(4) { width: 50%; }
@keyframes darma-loader-uiverse-dashboard-skeleton-card-skeletonSweep { to { background-position: -300% 0; } }

